sys_script_include.script:
var TableReferenceResolver = Class.create();
TableReferenceResolver.prototype = {
    initialize: function () {},

    resolveReferenceDisplayValuesForFilters: function (filters) {
        if (!Array.isArray(filters)) {
            return;
        }

        var self = this;
        filters.forEach(function (filter) {
            if (
                filter &&
                filter.type === "reference" &&
                filter.value &&
                !filter.displayValue
            ) {
                filter.displayValue = self.getReferenceDisplayValue(
                    filter.referenceTable,
                    filter.value,
                );
            }
        });
    },

    getReferenceDisplayValue: function (tableName, sysId) {
        if (!tableName || !sysId) {
            return "";
        }

        try {
            var gr = new GlideRecord(tableName);
            if (gr.get(sysId)) {
                return gr.getDisplayValue() || "";
            }
        } catch (error) {
            // Keep widget responses resilient even if lookup fails.
        }

        return "";
    },

    type: "TableReferenceResolver",
};
